"use strict";parserFactory.register("zeonic-republic.net",()=>new ZeonicrepublicParser);class ZeonicrepublicParser extends Parser{constructor(){super()}async getChapterUrls(e){let r=[...e.querySelectorAll("div.info a")];return 0===r.length&&(r=[...e.querySelectorAll("div.entry a")]),r.map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector("div#content")}extractTitleImpl(e){return e.querySelector("h2.title")}findCoverImageUrl(e){return null===e.querySelector("div.book-info .cover img")?util.getFirstImgSrc(e,"div.entry"):util.getFirstImgSrc(e,"div.book-info .cover")}}